<template><div class="modern-page"><section class="modern-hero"><h1>Relatórios</h1><p>Relatórios baseados em dados reais da base de dados. Exportação CSV/PDF simples no navegador.</p><div class="hero-actions"><button class="btn" @click="load">Actualizar</button><button class="btn btn-primary" @click="exportCsv">Exportar CSV</button><button class="btn" @click="exportPdf">Exportar PDF</button></div></section><div class="kpi-grid"><div class="kpi"><div class="label">Carteira</div><div class="value">{{mzn(portfolioTotal)}}</div></div><div class="kpi"><div class="label">Recebimentos</div><div class="value">{{mzn(paymentTotal)}}</div></div><div class="kpi warn"><div class="label">NPL</div><div class="value">{{npl.npl_rate||0}}%</div></div><div class="kpi danger"><div class="label">Em atraso</div><div class="value">{{mzn(npl.overdue_balance)}}</div></div></div><div class="grid-2"><div class="modern-card"><h2>Carteira por estado</h2><table class="modern-table"><thead><tr><th>Estado</th><th>Qtd.</th><th>Saldo</th></tr></thead><tbody><tr v-for="r in portfolio" :key="r.status"><td>{{r.status}}</td><td>{{r.count}}</td><td>{{mzn(r.total_balance)}}</td></tr></tbody></table></div><div class="modern-card"><h2>Pagamentos por método</h2><table class="modern-table"><thead><tr><th>Método</th><th>Qtd.</th><th>Total</th></tr></thead><tbody><tr v-for="r in payments" :key="r.method"><td>{{r.method}}</td><td>{{r.count}}</td><td>{{mzn(r.total)}}</td></tr></tbody></table></div></div></div></template>
<script setup>import {ref,computed,onMounted} from 'vue'; import {useToast} from 'vue-toastification'; import api from '@/services/api'; const toast=useToast(); const portfolio=ref([]),payments=ref([]),npl=ref({}); const mzn=v=>Number(v||0).toLocaleString('pt-MZ',{style:'currency',currency:'MZN',maximumFractionDigits:0}); const portfolioTotal=computed(()=>portfolio.value.reduce((s,r)=>s+Number(r.total_balance||0),0)); const paymentTotal=computed(()=>payments.value.reduce((s,r)=>s+Number(r.total||0),0)); async function load(){try{const [a,b,c]=await Promise.all([api.get('/reports/portfolio'),api.get('/reports/payments-summary'),api.get('/reports/npl')]); portfolio.value=a.data.data||[]; payments.value=b.data.data||[]; npl.value=c.data.data||{} }catch(e){toast.error(e.response?.data?.message||'Erro ao carregar relatórios')}} function exportCsv(){const rows=[['Carteira'],['Estado','Qtd','Saldo'],...portfolio.value.map(r=>[r.status,r.count,r.total_balance]),[],['Pagamentos'],['Método','Qtd','Total'],...payments.value.map(r=>[r.method,r.count,r.total])]; const blob=new Blob([rows.map(r=>r.join(';')).join('\n')],{type:'text/csv'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='relatorio.csv'; a.click(); URL.revokeObjectURL(a.href)} function exportPdf(){window.print()} onMounted(load)</script>
